import { readFileSync } from "fs";
import { join } from "path";

const { version } = JSON.parse(readFileSync(join(__dirname, "package.json"), "utf8")) as { version: string };
let piVersion = "unknown";
try {
  const piPkgPath = join(__dirname, "node_modules/@earendil-works/pi-coding-agent/package.json");
  piVersion = (JSON.parse(readFileSync(piPkgPath, "utf8")) as { version: string }).version;
} catch { /* package not found, use default */ }

const nextConfig: NextConfig = {
  serverExternalPackages: [
    "@earendil-works/pi-coding-agent",
    "@earendil-works/pi-ai",
    "@earendil-works/pi-agent-core",
    "@earendil-works/pi-tui",
    "glob",
    "@lydell/node-pty",
  ],
  outputFileTracingExcludes: {
    "/*": [".pi/**/*"],
    "/api/*": [".pi/**/*"],
  },
  allowedDevOrigins: ["192.168.*.*", "127.0.0.1", "localhost"],
  env: {
    NEXT_PUBLIC_APP_VERSION: version,
    NEXT_PUBLIC_PI_VERSION: piVersion,
  },
};

export default nextConfig;

#!/usr/bin/env node
"use strict";

/**
 * Build helper for the local Next.js production bundle.
 *
 * Author: lichong <lichong@uino.com>
 */

// eslint-disable-next-line @typescript-eslint/no-require-imports
const { spawnSync } = require("child_process");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const { mkdirSync } = require("fs");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const { join } = require("path");

const projectRoot = join(__dirname, "..");
const buildHome = join(projectRoot, ".next-build-home");

/**
 * Ensures the temporary build home exists.
 *
 * @param {string} dir Temporary home directory used only by the build process.
 */
function ensureBuildHome(dir) {
  mkdirSync(dir, { recursive: true });
}

/**
 * Creates an environment for Next.js build that avoids protected Windows home junctions.
 *
 * @param {NodeJS.ProcessEnv} baseEnv Current process environment.
 * @param {string} homeDir Temporary home directory used by build-only discovery.
 * @returns {NodeJS.ProcessEnv} Environment passed to the build child process.
 */
function createBuildEnv(baseEnv, homeDir) {
  return {
    ...baseEnv,
    HOME: homeDir,
    USERPROFILE: homeDir,
  };
}

ensureBuildHome(buildHome);

const result = spawnSync(
  process.execPath,
  [join(projectRoot, "node_modules", "next", "dist", "bin", "next"), "build", "--webpack"],
  {
    cwd: projectRoot,
    stdio: "inherit",
    env: createBuildEnv(process.env, buildHome),
  }
);

process.exit(result.status ?? 1);

#!/usr/bin/env node
"use strict";

// eslint-disable-next-line @typescript-eslint/no-require-imports
const { spawn } = require("child_process");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const path = require("path");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const fs = require("fs");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const { parseArgs } = require("util");

const pkgDir = path.join(__dirname, "..");
const nextDir = path.join(pkgDir, ".next");

// Resolve next's CLI entry directly to avoid relying on .bin symlinks (which
// may not exist when installed via npx).
let nextBin;
try {
  nextBin = require.resolve("next/dist/bin/next", { paths: [pkgDir] });
} catch {
  // Fallback: locate next package root and derive the bin path manually.
  try {
    const nextPkg = require.resolve("next/package.json", { paths: [pkgDir] });
    nextBin = path.join(path.dirname(nextPkg), "dist", "bin", "next");
  } catch {
    nextBin = path.join(pkgDir, "node_modules", "next", "dist", "bin", "next");
  }
}

const { values: cliArgs } = parseArgs({
  options: {
    port:         { type: "string", short: "p" },
    hostname:     { type: "string", short: "H" },
    proxy:        { type: "string" },
    "socks-proxy": { type: "string" },
    "no-proxy":  { type: "string" },
  },
  strict: false,
});

const port       = cliArgs.port     ?? process.env.PORT     ?? "30141";
const hostname   = cliArgs.hostname ?? process.env.HOSTNAME ?? null;
const httpProxy  = cliArgs.proxy ?? process.env.PROXY_URL ?? process.env.HTTP_PROXY ?? process.env.http_proxy ?? null;
const socksProxy = cliArgs["socks-proxy"] ?? process.env.SOCKS_PROXY_URL ?? process.env.ALL_PROXY ?? process.env.all_proxy ?? null;
const noProxy    = cliArgs["no-proxy"] ?? process.env.NO_PROXY ?? process.env.no_proxy ?? null;

if (!fs.existsSync(nextDir)) {
  console.error("Build artifacts not found. Please report this issue.");
  process.exit(1);
}

const nextArgs = ["start", "-p", port];
if (hostname) nextArgs.push("-H", hostname);

function appendNodeOption(current, option) {
  const parts = (current ?? "").split(/\s+/).filter(Boolean);
  return parts.includes(option) ? current ?? "" : [...parts, option].join(" ");
}

function createRuntimeEnv(baseEnv) {
  const env = { ...baseEnv };
  if (httpProxy) {
    env.HTTP_PROXY = httpProxy;
    env.HTTPS_PROXY = httpProxy;
    env.http_proxy = httpProxy;
    env.https_proxy = httpProxy;
  }
  if (socksProxy) {
    env.ALL_PROXY = socksProxy;
    env.all_proxy = socksProxy;
  }
  if (noProxy) {
    env.NO_PROXY = noProxy;
    env.no_proxy = noProxy;
  }
  if (httpProxy || socksProxy || noProxy) {
    env.NODE_OPTIONS = appendNodeOption(env.NODE_OPTIONS, "--use-env-proxy");
  }
  return env;
}

// Always run next's JS entry with node directly — avoids .bin symlink issues
// and path-with-spaces problems on Windows when shell: true is used.
const child = spawn(process.execPath, [nextBin, ...nextArgs], {
  cwd: pkgDir,
  stdio: ["inherit", "pipe", "inherit"],
  env: createRuntimeEnv(process.env),
});

let browserOpened = false;
const url = `http://${hostname ?? "localhost"}:${port}`;

child.stdout.on("data", (chunk) => {
  const text = chunk.toString();
  process.stdout.write(text);
  if (!browserOpened && text.includes("Ready")) {
    browserOpened = true;
    const isWindows = process.platform === "win32";
    const isMac = process.platform === "darwin";
    const openCmd = isWindows ? "start" : isMac ? "open" : "xdg-open";
    spawn(openCmd, [url], { shell: isWindows, stdio: "ignore", detached: true }).unref();
  }
});

child.on("exit", (code) => process.exit(code ?? 0));

